import os
import anthropic

# Map of provider name → (env var name, required flag)
PROVIDER_KEYS: dict[str, tuple[str, bool]] = {
    "anthropic": ("ANTHROPIC_API_KEY", True),
    "openai":    ("OPENAI_API_KEY",    False),  # optional in this app
    "gemini":    ("GOOGLE_API_KEY",    False),
}


def load_api_keys(
    providers: dict[str, tuple[str, bool]],
) -> dict[str, str]:
    """
    Load and validate API keys from environment variables.
    Raises EnvironmentError listing all missing required keys.
    """
    keys: dict[str, str] = {}
    missing_required: list[str] = []

    for provider, (env_var, required) in providers.items():
        value = os.environ.get(env_var, "").strip()
        if value:
            keys[provider] = value
        elif required:
            missing_required.append(env_var)

    if missing_required:
        raise EnvironmentError(
            f"Missing required API keys: {', '.join(missing_required)}. "
            "Set them as environment variables before starting."
        )

    return keys


keys = load_api_keys(PROVIDER_KEYS)
print(f"Loaded keys for: {list(keys.keys())}")

# Build only the clients whose keys are present
if "anthropic" in keys:
    anthropic_client = anthropic.Anthropic(api_key=keys["anthropic"])
    print("Anthropic client ready")
